# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.

Prevent race conditions.
# Category: race_condition

import akka.actor.Actor
import akka.actor.Props

object AccountActor {
  case class Deposit(amount: Double)
  case class Withdrawal(amount: Double)
  case class GetBalance(replyTo: akka.actor.ActorRef)
  
  def props(initialBalance: Double) = Props(new AccountActor(initialBalance))
}

class AccountActor(initialBalance: Double) extends Actor {
  import AccountActor._
  
  var balance = initialBalance
  
  def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! "Deposit successful"
      
    case Withdrawal(amount) =>
      if (balance >= amount) {
        balance -= amount
        sender() ! "Withdrawal successful"
      } else {
        sender() ! "Insufficient funds"
      }
      
    case GetBalance(replyTo) =>
      replyTo ! balance
  }
}